// Bundles Prism core + a curated language set into static files under
// public/prism/ so both the SPA and the static-site export can serve them.
//
// Keep the language list in sync with src/lib/highlight.ts — the SPA's
// preview uses its own ESM imports, but the static-site export ships this
// bundle verbatim and exported pages rely on it for highlighting.
import { readFileSync, writeFileSync, mkdirSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const here = dirname(fileURLToPath(import.meta.url));
const clientRoot = resolve(here, '..');
const prismRoot = resolve(clientRoot, 'node_modules/prismjs');
const outDir = resolve(clientRoot, 'public/prism');

const languages = [
  // Order matters: clike is a dependency of many, markup/css must come early.
  'prism-markup.min.js',
  'prism-css.min.js',
  'prism-clike.min.js',
  'prism-javascript.min.js',
  'prism-typescript.min.js',
  'prism-jsx.min.js',
  'prism-tsx.min.js',
  'prism-json.min.js',
  'prism-yaml.min.js',
  'prism-toml.min.js',
  'prism-ini.min.js',
  'prism-bash.min.js',
  'prism-python.min.js',
  'prism-csharp.min.js',
  'prism-rust.min.js',
  'prism-go.min.js',
  'prism-java.min.js',
  'prism-sql.min.js',
  'prism-markdown.min.js',
  'prism-diff.min.js',
  'prism-docker.min.js',
];

const header = '/* Prism bundle generated by build-prism-bundle.mjs — do not edit. */\n';
const core = readFileSync(resolve(prismRoot, 'prism.js'), 'utf8');
const parts = [header, core];
for (const lang of languages) {
  parts.push(readFileSync(resolve(prismRoot, 'components', lang), 'utf8'));
}
// The core script registers an auto-highlight hook on DOMContentLoaded. That
// fires once before the SPA router has injected any content, so the exported
// page does the work via an explicit Prism.highlightAll() at end of body.
const bundle = parts.join('\n');

// GitHub-style palette, light + dark via prefers-color-scheme. Self-contained
// so the exported site has no external dependencies.
const themeCss = `/* Prism theme generated by build-prism-bundle.mjs — do not edit. */
code[class*="language-"], pre[class*="language-"] {
  color: inherit;
  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace;
  font-size: 0.875em;
  line-height: 1.5;
  tab-size: 2;
  hyphens: none;
}
:root {
  --sg-syn-comment: #6a737d;
  --sg-syn-punct: #24292e;
  --sg-syn-tag: #22863a;
  --sg-syn-string: #032f62;
  --sg-syn-keyword: #d73a49;
  --sg-syn-number: #005cc5;
  --sg-syn-function: #6f42c1;
  --sg-syn-variable: #e36209;
}
@media (prefers-color-scheme: dark) {
  :root {
    --sg-syn-comment: #8b949e;
    --sg-syn-punct: #c9d1d9;
    --sg-syn-tag: #7ee787;
    --sg-syn-string: #a5d6ff;
    --sg-syn-keyword: #ff7b72;
    --sg-syn-number: #79c0ff;
    --sg-syn-function: #d2a8ff;
    --sg-syn-variable: #ffa657;
  }
}
.token.comment, .token.prolog, .token.cdata { color: var(--sg-syn-comment); font-style: italic; }
.token.punctuation { color: var(--sg-syn-punct); }
.token.tag, .token.selector, .token.attr-name, .token.builtin { color: var(--sg-syn-tag); }
.token.string, .token.char, .token.attr-value, .token.regex { color: var(--sg-syn-string); }
.token.keyword, .token.atrule, .token.important, .token.rule, .token.boolean, .token.operator { color: var(--sg-syn-keyword); }
.token.number, .token.hexcode, .token.unit { color: var(--sg-syn-number); }
.token.function, .token.class-name { color: var(--sg-syn-function); }
.token.variable, .token.symbol, .token.property, .token.constant, .token.entity { color: var(--sg-syn-variable); }
.token.italic { font-style: italic; }
.token.bold { font-weight: 600; }
`;

mkdirSync(outDir, { recursive: true });
writeFileSync(resolve(outDir, 'prism.bundle.js'), bundle);
writeFileSync(resolve(outDir, 'prism.theme.css'), themeCss);
console.log(`Wrote Prism bundle (${bundle.length} bytes) and theme (${themeCss.length} bytes) to ${outDir}`);
